try {
  const body = $('Webhook').first().json.body || $('Webhook').first().json;
  const mode = body.mode || 'plan';
  const q1 = body.q1 || '';
  const q2 = body.q2 || 'Telegram';
  const kbContext = body.kb_context || '';
  const correction = body.correction || '';
  const lang = body.lang || 'ru';

  const PLAN_PROMPT = `Ты контент-менеджер с 10-летним опытом. Создай оригинальный контент-план на 7 публикаций для следующего запроса.

Запрос пользователя:
Ниша/тема/аудитория/цель: ${q1}
Платформа: ${q2}
${kbContext ? '\nКонтекст из базы знаний пользователя:\n' + kbContext : ''}
${correction ? '\nПожелания по корректировке: ' + correction : ''}

Требования:
- 7 дней, по одной публикации в день
- 30% вовлекающий контент, 30% экспертный, 20% продающий, 20% развлекательный
- Цепляющие заголовки, никаких хэштегов
- Формат адаптирован под платформу: ${q2}
- Markdown для Telegram (звёздочки для жирного), до 3800 символов

Формат каждого блока:
*День N*
*Формат:* [тип контента]
*Заголовок:* [заголовок]
*Суть:* [краткое описание]
'━━━ 🌿 ━━━'

Не задавай вопросов, не добавляй хэштеги, создай финальный результат.`;

  const POST_PROMPT = `Ты профессиональный копирайтер с 10-летним опытом. Напиши пост по запросу пользователя.

Запрос пользователя:
Тип/тема/аудитория: ${q1}
Платформа: ${q2}
${kbContext ? '\nКонтекст из базы знаний пользователя:\n' + kbContext : ''}
${correction ? '\nПожелания по корректировке: ' + correction : ''}

Требования:
- Объём 2500–3800 символов
- Цепляющий заголовок, сторителлинг, призыв к действию
- Формат адаптирован под платформу: ${q2}
- Markdown для Telegram, до 3800 символов
- Не добавляй хэштеги

Формат:
*Заголовок*
[Основной текст поста]

Создай финальный результат без вопросов.`;

  const prompt = mode === 'post' ? POST_PROMPT : PLAN_PROMPT;
  return [{ json: { prompt, mode, q1, q2, lang } }];
} catch(e) {
  return [{ json: { _error: true, error: 'Prepare prompt error: ' + e.message } }];
}

try {
  const input = items[0].json;
  if (input._error || input.error) {
    return [{ json: { error: input.error || input._error } }];
  }
  // Extract content from OpenAI response
  let content = '';
  if (input.message && input.message.content) {
    content = input.message.content;
  } else if (input.choices && input.choices[0]) {
    content = input.choices[0].message?.content || input.choices[0].text || '';
  } else if (typeof input.content === 'string') {
    content = input.content;
  } else {
    content = JSON.stringify(input);
  }
  return [{ json: { content: content.trim() } }];
} catch(e) {
  return [{ json: { error: 'Parse response error: ' + e.message } }];
}
